#!/usr/bin/env node
/**
 * Bundle the chip-inline-entry.ts into a self-contained JavaScript string.
 *
 * This script uses esbuild to:
 * 1. Bundle chip-inline-entry.ts with all dependencies (ChipPlayer, PatternBuilder)
 * 2. Output an IIFE that exposes setupChipBridge globally
 * 3. Convert the bundled JS to a TypeScript string export
 */

import { build } from 'esbuild';
import { writeFileSync, mkdirSync, existsSync } from 'fs';
import { join, dirname } from 'path';
import { fileURLToPath } from 'url';

const __filename = fileURLToPath(import.meta.url);
const __dirname = dirname(__filename);

const ENTRY_FILE = join(__dirname, '..', 'src', 'chip', 'chip-inline-entry.ts');
const OUTPUT_DIR = join(__dirname, '..', 'src', 'chip');
const OUTPUT_TS = join(OUTPUT_DIR, 'chip-inline.generated.ts');

// Resolve to the pre-built player dist (avoids Vite-specific ?raw imports in source)
const PLAYER_DIST = join(__dirname, '..', '..', '..', 'vendor', 'WebOPL', 'packages', 'chip-composer-player', 'dist', 'chip-composer-player.js');

async function bundleChipInline() {
  console.log('Bundling chip-inline-entry.ts...');

  // Bundle with esbuild
  const result = await build({
    entryPoints: [ENTRY_FILE],
    bundle: true,
    format: 'iife',
    globalName: 'ChipInline',
    minify: false, // Keep readable for debugging
    sourcemap: false,
    write: false, // Don't write to disk, capture output
    target: 'es2020',
    platform: 'browser',
    // Don't externalize anything - bundle everything into one file
    external: [],
    // Resolve @chip-composer/player to its pre-built dist bundle
    // (source uses Vite-specific ?raw imports that esbuild can't handle)
    alias: {
      '@chip-composer/player': PLAYER_DIST,
    },
  });

  if (result.outputFiles.length === 0) {
    throw new Error('esbuild produced no output');
  }

  const bundledCode = result.outputFiles[0].text;

  // Escape backticks and ${} for template literal
  const escapedCode = bundledCode
    .replace(/\\/g, '\\\\')
    .replace(/`/g, '\\`')
    .replace(/\$\{/g, '\\${');

  // Generate TypeScript export
  const tsContent = `/* eslint-disable max-lines */
/**
 * Auto-generated from chip-inline-entry.ts
 * DO NOT EDIT THIS FILE DIRECTLY - edit the .ts source instead.
 *
 * Bundled chip bridge for standalone HTML exports.
 * Run "npm run build:chip" to regenerate this file.
 */
export const CHIP_INLINE_JS = \`${escapedCode}\`
`;

  // Ensure output directory exists
  if (!existsSync(OUTPUT_DIR)) {
    mkdirSync(OUTPUT_DIR, { recursive: true });
  }

  writeFileSync(OUTPUT_TS, tsContent);
  console.log(`Generated: chip-inline.generated.ts (${bundledCode.length} bytes)`);
}

bundleChipInline().catch((err) => {
  console.error('Failed to bundle chip inline:', err);
  process.exit(1);
});
